    expect(activeColumnWidth(controller, output, desktop)).toEqual({
      kind: "proportion",
      value: 0.6,
    });
    expect(active.window.frameGeometry.width).toBe(584);
    expect(controller.decreaseColumnWidth()).toBe(true);
