    Object.defineProperty(setup.fixture.workspace, "clientArea", {
      configurable: true,
      value: (
        option: number,
        output: KWinOutput,
        desktop: KWinVirtualDesktop,
      ) => {
        const area = originalClientArea(option, output, desktop);
        return { ...area, width: area.width - 100 };
      },
    });

