  it.each(["throws", "clamps"] as const)(
    "compensates a pointer resize when a write %s and accepts the next resize",
    (rejection) => {
      const setup = createPointerResizeRuntimeFixture();
      const beforeLayout = setup.layout.snapshot(
        outputId(setup.output.name),
        desktopId(setup.desktop.id),
        FALLBACK_ACTIVITY_ID,
      );
      const passiveFrame = { ...setup.passive.window.frameGeometry };
      const activeFrame = { ...setup.active.window.frameGeometry };
      const beforeFrames = [passiveFrame, activeFrame];
      const passiveAttempts: KWinWindow["frameGeometry"][] = [];
      const activeAttempts: KWinWindow["frameGeometry"][] = [];
      const publicationCount = setup.published.length;
      const warning = vi.spyOn(console, "warn").mockImplementation(() => {});

      beginPointerColumnResize(
        setup,
        pointerResizeAcceptedFrame(activeFrame, "left", 550),
      );
      setup.passive.setWriteBehavior((frame, commit) => {
        passiveAttempts.push({ ...frame });
        commit();
      });
      setup.active.setWriteBehavior((frame, commit) => {
        activeAttempts.push({ ...frame });

        if (activeAttempts.length === 1) {
          if (rejection === "throws") {
            throw new Error("geometry rejected");
          }

          setup.active.setFrameGeometry({
            ...frame,
            width: frame.width - 1,
          });
          return;
        }

        commit();
      });

      try {
        finishPointerColumnResize(setup);
      } finally {
        setup.passive.setWriteBehavior(null);
        setup.active.setWriteBehavior(null);
        warning.mockRestore();
      }

      expect(passiveAttempts).toHaveLength(2);
      expect(activeAttempts).toHaveLength(2);
      expect(passiveAttempts[0]).toMatchObject({ width: 550, x: 10 });
      expect(activeAttempts[0]).toMatchObject({ width: 550, x: 10 });
      expect(passiveAttempts[1]).toEqual(beforeFrames[0]);
      expect(activeAttempts[1]).toEqual(beforeFrames[1]);
      expect(
        setup.layout.snapshot(
          outputId(setup.output.name),
          desktopId(setup.desktop.id),
          FALLBACK_ACTIVITY_ID,
        ),
      ).toEqual(beforeLayout);
      expect([
        setup.passive.window.frameGeometry,
        setup.active.window.frameGeometry,
      ]).toEqual(beforeFrames);
      expect(setup.published).toHaveLength(publicationCount);

      beginPointerColumnResize(
        setup,
        pointerResizeAcceptedFrame(activeFrame, "right", 520),
      );
      finishPointerColumnResize(setup);

      expect(
        activeColumnWidth(setup.controller, setup.output, setup.desktop),
      ).toEqual({ kind: "fixed", value: 520 });
      expect(setup.passive.window.frameGeometry.width).toBe(520);
      expect(setup.active.window.frameGeometry.width).toBe(520);
      expect(setup.published).toHaveLength(publicationCount + 1);
    },
  );

  it("reinserts a dragged tiled window into a target column and stack slot", () => {
    const output = createOutput("DP-1", 0);
    const desktop = { id: "desktop-1" };
    const target = createTrackedWindow("target", output, desktop);
    const dragged = createTrackedWindow("dragged", output, desktop);
    const fixture = createWorkspace(
      output,
      desktop,
      [output],
      [desktop],
      [target.window, dragged.window],
    );
    const scheduler = new ManualScheduler();
    const published: string[] = [];
    const previews: KWinWindow["frameGeometry"][] = [];
    let hiddenPreviews = 0;
    const controller = new RuntimeController(fixture.workspace, {
      clientAreaOption: 2,
      gap: 10,
      hidePointerDropPreview: () => {
        hiddenPreviews += 1;
      },
      onLayoutStateChanged: (document) => published.push(document),
      schedule: scheduler.schedule,
      showPointerDropPreview: (frame) => previews.push({ ...frame }),
    });

    controller.start();
    expect(testLayoutColumns(controller, output, desktop)).toEqual([
      { id: "column:target", windowIds: ["target"] },
      { id: "column:dragged", windowIds: ["dragged"] },
    ]);
    Object.defineProperty(dragged.window, "move", {
      configurable: true,
      value: true,
    });
    dragged.moveResizedChanged.emit();
    dragged.interactiveMoveResizeStarted.emit();
    const firstTargetFrame = { ...target.window.frameGeometry };
    dragged.setFrameGeometry({ height: 780, width: 485, x: 80, y: 400 });
    fixture.setCursorPosition(200, 600);
    fixture.setCursorPosition(200, 650);
    flushManualScheduler(scheduler);

    expect(previews).toEqual([
      {
        ...firstTargetFrame,
        height: firstTargetFrame.height / 2,
        y: firstTargetFrame.y + firstTargetFrame.height / 2,
      },
    ]);
    Object.defineProperty(dragged.window, "move", {
      configurable: true,
      value: false,
    });
    dragged.moveResizedChanged.emit();
    dragged.interactiveMoveResizeFinished.emit();
    flushManualScheduler(scheduler);

    expect(hiddenPreviews).toBe(1);
    expect(testLayoutColumns(controller, output, desktop)).toEqual([
      { id: "column:target", windowIds: ["target", "dragged"] },
    ]);
    expect(target.window.frameGeometry.x).toBe(10);
    expect(dragged.window.frameGeometry.x).toBe(10);
    expect(dragged.window.frameGeometry.width).toBe(
      target.window.frameGeometry.width,
    );
    expect(target.window.frameGeometry.y).toBeLessThan(
      dragged.window.frameGeometry.y,
    );
    expect(fixture.workspace.activeWindow).toBe(dragged.window);
    expect(controller.lastWriteCount).toBeGreaterThan(0);
    expect(published).toHaveLength(2);

    Object.defineProperty(dragged.window, "move", {
      configurable: true,
      value: true,
    });
    dragged.moveResizedChanged.emit();
    dragged.interactiveMoveResizeStarted.emit();
    const secondTargetFrame = { ...target.window.frameGeometry };
    dragged.setFrameGeometry({
      ...dragged.window.frameGeometry,
      x: 120,
      y: 80,
    });
    fixture.setCursorPosition(200, 100);
    flushManualScheduler(scheduler);

    expect(previews[previews.length - 1]).toEqual({
      ...secondTargetFrame,
      height: Math.round(secondTargetFrame.height / 2),
    });
    Object.defineProperty(dragged.window, "move", {
      configurable: true,
      value: false,
    });
    dragged.moveResizedChanged.emit();
    dragged.interactiveMoveResizeFinished.emit();
    flushManualScheduler(scheduler);

    expect(testLayoutColumns(controller, output, desktop)).toEqual([
      { id: "column:target", windowIds: ["dragged", "target"] },
    ]);
    expect(dragged.window.frameGeometry.y).toBeLessThan(
      target.window.frameGeometry.y,
    );
    expect(hiddenPreviews).toBe(2);
    expect(published).toHaveLength(3);
  });

  it.each([
    {
      cursor: { x: 220, y: 190 },
      dropTarget: "exact window" as const,
      expectedPreview: { height: 120, width: 420, x: 10, y: 130 },
    },
    {
      cursor: { x: 440, y: 130 },
      dropTarget: "empty gutter" as const,
      expectedPreview: { height: 240, width: 570, x: 430, y: 10 },
    },
  ])(
    "previews and tiles a manually floating window at an $dropTarget after resume",
    ({ cursor, dropTarget, expectedPreview }) => {
      const setup = createManualFloatingPointerDropRuntimeFixture();

      Object.defineProperty(setup.dragged.window, "move", {
        configurable: true,
        value: true,
      });
      setup.dragged.moveResizedChanged.emit();
      setup.dragged.interactiveMoveResizeStarted.emit();
      setup.dragged.setFrameGeometry({
        ...setup.dragged.window.frameGeometry,
        x: cursor.x - setup.dragged.window.frameGeometry.width / 2,
        y: cursor.y - setup.dragged.window.frameGeometry.height / 2,
      });
      setup.fixture.setCursorPosition(cursor.x, cursor.y);
      flushManualScheduler(setup.workScheduler);

      expect(setup.previews).toEqual([expectedPreview]);

      Object.defineProperty(setup.dragged.window, "move", {
        configurable: true,
        value: false,
      });
      setup.dragged.moveResizedChanged.emit();
      setup.dragged.interactiveMoveResizeFinished.emit();

      expect(setup.hiddenPreviewCount).toBe(1);
      expect(setup.controller.floatingCount).toBe(1);
      expect(
        testLayoutColumns(setup.controller, setup.output, setup.desktop),
      ).toEqual([{ id: "column:target", windowIds: ["target"] }]);

      flushManualScheduler(setup.workScheduler);
      expect(setup.controller.floatingCount).toBe(1);
      expect(setup.resumeScheduler.pendingCount).toBe(1);
      setup.resumeScheduler.flush();
      expect(setup.controller.floatingCount).toBe(1);
      expect(setup.workScheduler.pendingCount).toBeGreaterThan(0);
      flushManualScheduler(setup.workScheduler);

      const snapshot = runtimeLayout(setup.controller).snapshot(
        outputId(setup.output.name),
        desktopId(setup.desktop.id),
        FALLBACK_ACTIVITY_ID,
      );

      expect(setup.controller.floatingCount).toBe(0);
      expect(
        runtimeFloatingWindows(setup.controller).has(windowId("dragged")),
      ).toBe(false);
      expect(setup.fixture.workspace.activeWindow).toBe(setup.dragged.window);

      if (dropTarget === "exact window") {
        const targetColumn = snapshot.columns[0];

        expect(snapshot.columns).toHaveLength(1);
        expect(targetColumn).toMatchObject({
          id: "column:target",
          presentation: "stacked",
          selectedWindowId: "dragged",
          width: { kind: "fixed", value: 420 },
          windowIds: ["target", "dragged"],
        });
        expect(targetColumn && columnWindowHeights(targetColumn)).toEqual([
          { clientHeight: 240, kind: "fixed" },
          { kind: "auto", weight: 1 },
        ]);
      } else {
        const insertedColumn = snapshot.columns[1];

        expect(snapshot.columns.map((column) => column.windowIds)).toEqual([
          [windowId("target")],
          [windowId("dragged")],
        ]);
        expect(insertedColumn).toMatchObject({
          id: "column:dragged",
          presentation: "tabbed",
          selectedWindowId: "dragged",
          width: { kind: "fixed", value: 260 },
          windowIds: ["dragged"],
        });
        expect(insertedColumn && columnWindowHeights(insertedColumn)).toEqual([
          { kind: "auto", weight: 1 },
        ]);
      }
    },
  );

